以上即为当前 SW501 工程内二进制重排相关实现的步骤与逻辑说明。

ZMOrderFileCollector\.h 文件代码

\#import <Foundation/Foundation\.h>  

NS\_ASSUME\_NONNULL\_BEGIN  

/// 在冷启动早期调用一次即可：稍后在后台写出 order 文件路径（仅 Debug 且插桩开启时有效）。  
void ZMOrderFileScheduleExportAfterColdLaunch\(void \(^completion\)\(NSString \*\_Nullable orderFilePath\)\);  

NS\_ASSUME\_NONNULL\_END  


ZMOrderFileCollector\.m 文件代码

//  
//  ZMOrderFileCollector\.m  
//  SW501  
//  

\#import "ZMOrderFileCollector\.h"  

\#if SW501\_ORDER\_FILE\_INSTRUMENTATION  

\#import <dlfcn\.h>  
\#import <os/lock\.h>  
\#import <stdint\.h>  

static os\_unfair\_lock ZMOrderFileGuardLock = OS\_UNFAIR\_LOCK\_INIT;  
static NSMutableArray<NSValue \*> \*ZMOrderFilePCs;  

void \_\_sanitizer\_cov\_trace\_pc\_guard\_init\(uint32\_t \*start, uint32\_t \*stop\) \{  
    static uint64\_t N;  
    if \(start == stop || \*start\) \{  
        return;  
    \}  
    for \(uint32\_t \*x = start; x < stop; x\+\+\) \{  
        \*x = \(uint32\_t\)\+\+N;  
    \}  
\}  

void \_\_sanitizer\_cov\_trace\_pc\_guard\(uint32\_t \*guard\) \{  
    \(void\)guard;  
    void \*pc = \_\_builtin\_return\_address\(0\);  
    os\_unfair\_lock\_lock\(&ZMOrderFileGuardLock\);  
    if \(\!ZMOrderFilePCs\) \{  
        ZMOrderFilePCs = \[\[NSMutableArray alloc\] init\];  
    \}  
    \[ZMOrderFilePCs addObject:\[NSValue valueWithPointer:pc\]\];  
    os\_unfair\_lock\_unlock\(&ZMOrderFileGuardLock\);  
\}  

static void ZMOrderFileRunExport\(void \(^completion\)\(NSString \*\_Nullable orderFilePath\)\) \{  
    NSString \*excludeName = \[NSString stringWithFormat:@"\_%s", "ZMOrderFileRunExport"\];  
    \_\_sync\_synchronize\(\);  

    NSMutableArray<NSString \*> \*symbolNames = \[NSMutableArray array\];  
    os\_unfair\_lock\_lock\(&ZMOrderFileGuardLock\);  
    NSArray<NSValue \*> \*snapshot = \[ZMOrderFilePCs copy\];  
    \[ZMOrderFilePCs removeAllObjects\];  
    os\_unfair\_lock\_unlock\(&ZMOrderFileGuardLock\);  

    for \(NSValue \*boxed in snapshot\) \{  
        void \*pc = \[boxed pointerValue\];  
        Dl\_info info;  
        if \(pc && dladdr\(pc, &info\) && info\.dli\_sname\) \{  
            NSString \*name = @\(info\.dli\_sname\);  
            BOOL isObjc = \[name hasPrefix:@"\+\["\] || \[name hasPrefix:@"\-\["\];  
            NSString \*symbolName = nil;  
            if \(isObjc\) \{  
                symbolName = name;  
            \} else if \(\[name hasPrefix:@"\_"\]\) \{  
                symbolName = name;  
            \} else \{  
                symbolName = \[@"\_" stringByAppendingString:name\];  
            \}  
            \[symbolNames addObject:symbolName\];  
        \}  
    \}  

    if \(symbolNames\.count == 0\) \{  
        if \(completion\) \{  
            completion\(nil\);  
        \}  
        return;  
    \}  

    NSMutableOrderedSet<NSString \*> \*orderedUnique = \[\[NSMutableOrderedSet alloc\] init\];  
    for \(NSString \*name in symbolNames\) \{  
        if \(\!\[orderedUnique containsObject:name\]\) \{  
            \[orderedUnique addObject:name\];  
        \}  
    \}  
    NSMutableArray<NSString \*> \*funcs = \[\[orderedUnique array\] mutableCopy\];  
    \[funcs removeObject:excludeName\];  

    NSString \*funcStr = \[funcs componentsJoinedByString:@"\\n"\];  
    NSLog\(@"ZMOrderFile: collected %lu symbols \(preview first 8 lines\):\\n%@",  
          \(unsigned long\)funcs\.count,  
          \[\[funcs subarrayWithRange:NSMakeRange\(0, MIN\(funcs\.count, 8\)\)\] componentsJoinedByString:@"\\n"\]\);  

    NSString \*filePath = \[NSTemporaryDirectory\(\) stringByAppendingPathComponent:@"SW501\.generated\.order"\];  
    NSData \*data = \[funcStr dataUsingEncoding:NSUTF8StringEncoding\];  
    NSError \*error = nil;  
    BOOL ok = \[data writeToFile:filePath options:NSDataWritingAtomic error:&error\];  
    if \(\!ok\) \{  
        NSLog\(@"ZMOrderFile: write failed: %@", error\);  
    \}  
    if \(completion\) \{  
        completion\(ok ? filePath : nil\);  
    \}  
\}  

void ZMOrderFileScheduleExportAfterColdLaunch\(void \(^completion\)\(NSString \*\_Nullable orderFilePath\)\) \{  
    dispatch\_after\(dispatch\_time\(DISPATCH\_TIME\_NOW, \(int64\_t\)\(0\.02 \* NSEC\_PER\_SEC\)\),  
                   dispatch\_get\_global\_queue\(QOS\_CLASS\_UTILITY, 0\),  
                   ^\{  
                       ZMOrderFileRunExport\(completion\);  
                   \}\);  
\}  

\#else  

void ZMOrderFileScheduleExportAfterColdLaunch\(void \(^completion\)\(NSString \*\_Nullable orderFilePath\)\) \{  
    if \(completion\) \{  
        completion\(nil\);  
    \}  
\}  

\#endif  


BWAppDelegate\.m 文件代码

\- \(BOOL\)application:\(UIApplication \*\)application didFinishLaunchingWithOptions:\(NSDictionary \*\)launchOptions \{  
    ZMOrderFileScheduleExportAfterColdLaunch\(^\(NSString \*orderFilePath\) \{  
        if \(orderFilePath\.length > 0\) \{  
            XLog\(@"ZMOrderFile: generated order at %@", orderFilePath\);  
        \}  
    \}\);  

\}

__真机路径__

/private/var/mobile/Containers/Data/Application/4AE348BA\-BCF6\-406D\-898B\-DAA5BC4C5577/tmp/SW501\.generated\.order

说明：/private/var/mobile/Containers/\.\.\. 是真机沙盒里的路径，只存在于手机系统上，在 Mac 的访达里搜不到。正在确认代码里写入与回调逻辑，便于给出可操作步骤。

__为什么「找不到文件」？__

1\. 这个路径在手机上，不在 Mac 上

/private/var/mobile/Containers/Data/Application/\.\.\. 是 iOS 真机沙盒 里的绝对路径。在 Mac 的访达里搜这个路径 一定找不到，因为它根本不在你的电脑上。

要在真机里拿到文件，一般用下面两种方式之一：

- Xcode → Window → Devices and Simulators → 选中真机 → Installed Apps 里选中 SW501 → 齿轮 → Download Container…  
解压后进入：AppData/Documents、Library、tmp 等目录里找 __SW501\.generated\.order__（一般在 __tmp__ 下，和 NSTemporaryDirectory\(\) 对应）。
- 或用 模拟器 跑 Debug：容器在 Mac 本机磁盘上，用下面命令拿到应用数据根目录后再进 tmp：

xcrun simctl get\_app\_container booted com\.xiaoxun\.imibaby data

（若 bundle id 不同，把 com\.xiaoxun\.imibaby 换成你当前 scheme 的包名。）

__Mac 上Xcode路径__

/Users/zhangmeng/Desktop/com\.xiaoxun\.imibaby\\ 2026\-05\-16\\ 10:06\.07\.382\.xcappdata/AppData/tmp/SW501\.generated\.order

__验证效果：__  
使用 Instruments 的 System Trace 工具分析启动时的缺页中断次数，验证优化效果。  
使用 Instruments 分析启动路径  
为了确定启动时需要优先加载的函数和数据，可以使用 Instruments 的 System Trace 工具分析 App 的启动路径。__步骤如下：__

1. 打开 Xcode，选择 Product \-> Profile \-> System Trace。
2. 启动 App，记录启动过程中的系统调用和函数调用。
3. 分析启动路径，确定哪些函数和数据是启动时需要用到的
4. 记录TimeProfile：重排前/后的时间

