## <a id="lqwckrs6bwsr7slbdw7"></a>__加密热修复文件__

// 测试环境 本地加密文件  
\#if DEBUG  
    static func encryptPlainScirptToDocument\(\) \{  
      // 取路径  
        guard  
            let scriptUrl = Bundle\.main\.url\(forResource: "demo", withExtension: "mg"\),  
            let homePath = NSSearchPathForDirectoriesInDomains\(\.documentDirectory, \.userDomainMask, true\)\.first  
        else \{  
            fatalError\(\)  
        \}  
        do \{  
          // 取内容  
            let plainScriptString = try String\(contentsOf: scriptUrl\)  
            guard  
          // 加密  
                let plainScriptData = plainScriptString\.data\(using: \.utf8\),  
                let enecryptedData = \(plainScriptData as NSData\)\.aes128ParmEncrypt\(withKey: key, iv: iv\)  
            else \{  
                return  
            \}  
          // 获取加密路径  
            let encryptedPath = URL\(fileURLWithPath: homePath\)\.appendingPathComponent\("encrypted\_demo\.mg"\)  
            let fileManager = FileManager\.default  
          // 创建文件夹  
            if fileManager\.fileExists\(atPath: encryptedPath\.path\) == false \{  
                fileManager\.createFile\(atPath: encryptedPath\.path, contents: nil, attributes: nil\)  
            \}  
          // 写入文件  
            try enecryptedData\.write\(to: encryptedPath\)  
        \} catch \{  
            fatalError\(\)  
        \}  
    \}  
    \#endif

