## <a id="lqwcn0gi5isp9xbd8q"></a>__App获取加密后的文件__

static func fetch\(\) \{  
  // 开发环境 本地加密 测试热更新  
        \#if DEBUG  
        encryptPlainScirptToDocument\(\)  
        \#endif  
  // 初始化SDK 传入加密key 和iv  
        let context = MFContext\(aes128Key: key, iv: iv\)  
  // 获取家目录  
        let homeUrl = URL\(fileURLWithPath: NSSearchPathForDirectoriesInDomains\(\.documentDirectory, \.userDomainMask, true\)\.first\!\)  
  // 开发环境 直接使用测试文件 测试热更新  
\#if DEBUG  
        context\.evalMangoScript\(with: homeUrl\.appendingPathComponent\("encrypted\_demo\.mg"\)\)  
        return  
\#endif  
  // 请求热更新配置  
        reXiuFuProvider\.requestJson\(\.getAppVersion\) \{ result in   
            switch result \{  
            case let \.success\(json\):  
                guard  
                    let apkUrl = json\["apkUrl"\]\.string,  
                    let url = URL\(string: apkUrl\)  
                else \{  
                    return  
                \}  

                let fileName = apkUrl\.md5  
                let manager = FileManager\.default  

                let rexiufuPath = homeUrl\.appendingPathComponent\("rexiufu"\)  
                let pointer = UnsafeMutablePointer<ObjCBool>\.allocate\(capacity: 1\)  
                if manager\.fileExists\(atPath: rexiufuPath\.absoluteString, isDirectory: pointer\) == false \{  
                    try? manager\.createDirectory\(at: rexiufuPath, withIntermediateDirectories: true, attributes: nil\)  
                \}  
              // 取地址  
                let fileExistsUrl = rexiufuPath\.appendingPathComponent\(fileName\)  
              // 缓存存在 直接使用  
                if manager\.fileExists\(atPath: fileExistsUrl\.path\) \{  
                    context\.evalMangoScript\(with: fileExistsUrl\)  
                \} else \{  
                    // 下载新的热更新文件  
                    URLSession\.shared\.downloadTask\(with: url, completionHandler: \{ fileUrl, \_, \_ in  
                        guard let fileUrl = fileUrl else \{ return \}  
                        let toUrl = rexiufuPath\.appendingPathComponent\(fileName\)  
                                                                                  // 下载完成 从缓存目录移到保存的地址  
                        try? manager\.copyItem\(at: fileUrl, to: toUrl\)  
                                                                                  // 热更新加载文件  
                        context\.evalMangoScript\(with: toUrl\)  
                    \}\)\.resume\(\)  
                \}  
            case \.failure:  
                break  
            \}  
        \}  
    \}

